const input = $input.first().json;
const channel = input.channel || $('Validar Payload').item.json.channel;
const leadId = input.lead_id || $('Validar Payload').item.json.lead_id;

let success = false;
let result = 'unknown';

if (channel === 'instagram') {
  success = input.success === true || input.status === 'sent';
  result = success ? 'sent_instagram' : 'failed_instagram';
} else if (channel === 'whatsapp') {
  result = 'pending_whatsapp';
} else if (channel === 'linkedin') {
  result = 'pending_linkedin';
}

return [{json: {
  success,
  lead_id: leadId,
  channel,
  dispatch_result: result,
  timestamp: new Date().toISOString()
}}];
